// 跟踪当前位置信息
struct PositionTracker {
  std::string currentFile = "<input>";
  int currentLine = 1;
  int currentCol = 1;
  bool atLineStart = true;
  bool hasLeadingSpace = false;

  void reset() {
    currentFile = "<input>";
    currentLine = 1;
    currentCol = 1;
    atLineStart = true;
    hasLeadingSpace = false;
  }
};

PositionTracker tracker;

// 解析预处理指令，更新文件名和行号
void parsePreprocessingDirective(const std::string& line) {
  // 格式：# linenum "filename" flags
  size_t pos = 1; // 跳过 '#'

  // 跳过空白
  while (pos < line.size() && (line[pos] == ' ' || line[pos] == '\t')) pos++;

  // 读取行号
  size_t numStart = pos;
  while (pos < line.size() && line[pos] >= '0' && line[pos] <= '9') pos++;

  if (pos > numStart) {
    tracker.currentLine = std::stoi(line.substr(numStart, pos - numStart));
  }

  // 跳过空白
  while (pos < line.size() && (line[pos] == ' ' || line[pos] == '\t')) pos++;

  // 读取文件名（在引号中）
  if (pos < line.size() && line[pos] == '"') {
    pos++; // 跳过开头的 '"'
    size_t fileStart = pos;
    while (pos < line.size() && line[pos] != '"') pos++;
    tracker.currentFile = line.substr(fileStart, pos - fileStart);
  }
}

void
print_token(const antlr4::Token* token,
            const antlr4::CommonTokenStream& tokens,
            std::ofstream& outFile,
            const antlr4::Lexer& lexer)
{
  auto& vocabulary = lexer.getVocabulary();

  auto tokenTypeName =
    std::string(vocabulary.getSymbolicName(token->getType()));

  if (tokenTypeName.empty())
    tokenTypeName = "<UNKNOWN>"; // 处理可能的空字符串情况

  if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
    tokenTypeName = tokenTypeMapping[tokenTypeName];
  }

  // 构建位置信息
  std::string locInfo = " Loc=<" + tracker.currentFile + ":" + 
                        std::to_string(tracker.currentLine) + ":" + 
                        std::to_string(tracker.currentCol) + ">";

  bool startOfLine = tracker.atLineStart;
  bool leadingSpace = tracker.hasLeadingSpace && !tracker.atLineStart;

  if (token->getText() != "<EOF>")
    outFile << tokenTypeName << " '" << token->getText() << "'";
  else
    outFile << tokenTypeName << " '"
            << "'";
  if (startOfLine)
    outFile << "\t [StartOfLine]";
  if (leadingSpace)
    outFile << " [LeadingSpace]";
  outFile << locInfo << std::endl;

  // 更新位置跟踪器
  std::string tokenText = token->getText();
  if (tokenText != "<EOF>") {
    // 更新列号
    tracker.currentCol += tokenText.length();
    tracker.atLineStart = false;
    tracker.hasLeadingSpace = false;
  }
}

