};

int main(int argc, char* argv[]) {
  if (argc != 3) {
    std::cout << "Usage: " << argv[0] << " <input> <output>\n";
    return -1;
  }

  std::ifstream inFile(argv[1]);
  if (!inFile) {
    std::cout << "Error: unable to open input file: " << argv[1] << '\n';
    return -2;
  }

  std::ofstream outFile(argv[2]);
  if (!outFile) {
    std::cout << "Error: unable to open output file: " << argv[2] << '\n';
    return -3;
  }

  std::cout << "程序 '" << argv[0] << std::endl;
  std::cout << "输入 '" << argv[1] << std::endl;
  std::cout << "输出 '" << argv[2] << std::endl;

  // 读取完整文件
  std::string content((std::istreambuf_iterator<char>(inFile)),
                      std::istreambuf_iterator<char>());
  inFile.close();

  // 解析预处理指令，构建逻辑行到源文件的映射
  std::string currentFile = argv[1];
  std::vector<std::pair<std::string, int>> logicalLines; // line content -> original line num
  std::vector<std::string> lineFiles; // file for each logical line
  int currentLineNum = 1;

  std::istringstream iss(content);
  std::string line;

  while (std::getline(iss, line)) {
    size_t pos = 0;
    while (pos < line.size() && (line[pos] == ' ' || line[pos] == '\t')) pos++;

    if (pos < line.size() && line[pos] == '#') {
      // 预处理指令 # linenum "filename"
      size_t numPos = pos + 1;
      while (numPos < line.size() && (line[numPos] == ' ' || line[numPos] == '\t')) numPos++;

      size_t numStart = numPos;
      while (numPos < line.size() && line[numPos] >= '0' && line[numPos] <= '9') numPos++;

      if (numPos > numStart) {
        currentLineNum = std::stoi(line.substr(numStart, numPos - numStart));
      }

      while (numPos < line.size() && (line[numPos] == ' ' || line[numPos] == '\t')) numPos++;

      if (numPos < line.size() && line[numPos] == '"') {
        numPos++;
        size_t fileStart = numPos;
        while (numPos < line.size() && line[numPos] != '"') numPos++;
        currentFile = line.substr(fileStart, numPos - fileStart);
      }
      // 跳过预处理行
    } else {
      logicalLines.push_back({line, currentLineNum});
      lineFiles.push_back(currentFile);
      currentLineNum++;
    }
  }

  // 构建不含预处理指令的内容
  std::string processedContent;
  for (const auto& p : logicalLines) {
    processedContent += p.first + "\n";
  }

  // 使用 ANTLR 词法分析
  antlr4::ANTLRInputStream input(processedContent);
  SYsULexer lexer(&input);
  antlr4::CommonTokenStream tokens(&lexer);
  tokens.fill();

  // 为每个 token 查找其在源代码中的位置
  int logicalLineIdx = 0;
  int lineCol = 1;

  auto& vocabulary = lexer.getVocabulary();

  for (auto&& token : tokens.getTokens()) {
    std::string tokenText = token->getText();

    if (tokenText == "<EOF>") {
      outFile << "eof ''\t\tLoc=<" << lineFiles[logicalLineIdx] << ":" 
              << logicalLines[logicalLineIdx].second << ":" << lineCol << ">" << std::endl;
      break;
    }

    auto tokenTypeName = std::string(vocabulary.getSymbolicName(token->getType()));
    if (tokenTypeName.empty()) tokenTypeName = "<UNKNOWN>";
    if (tokenTypeMapping.find(tokenTypeName) != tokenTypeMapping.end()) {
      tokenTypeName = tokenTypeMapping[tokenTypeName];
    }

    // 在当前逻辑行中查找 token
    bool found = false;
    while (!found && logicalLineIdx < (int)logicalLines.size()) {
      const std::string& srcLine = logicalLines[logicalLineIdx].first;
      std::string srcFile = lineFiles[logicalLineIdx];
      int srcLineNum = logicalLines[logicalLineIdx].second;

      // 从 lineCol 开始查找
      size_t searchStart = lineCol - 1;
      if (searchStart >= srcLine.size()) {
        // 当前行已处理完，移到下一行
        logicalLineIdx++;
        lineCol = 1;
        continue;
      }

      size_t foundPos = srcLine.find(tokenText, searchStart);

      if (foundPos != std::string::npos) {
        // 找到 token
        bool atLineStart = (searchStart == 0 || 
                           srcLine.substr(0, foundPos).find_first_not_of(" \t") == std::string::npos);
        bool hasLeadingSpace = (foundPos > 0 && 
                                srcLine.substr(0, foundPos).find_first_of(" \t") != std::string::npos);

        // 更精确的判断
        if (foundPos == 0) {
          atLineStart = true;
          hasLeadingSpace = false;
        } else {
          std::string prefix = srcLine.substr(0, foundPos);
          atLineStart = (prefix.find_first_not_of(" \t") == std::string::npos);
          hasLeadingSpace = !prefix.empty();
        }

        outFile << tokenTypeName << " '" << tokenText << "'";
        if (atLineStart) {
          outFile << "\t [StartOfLine]";
        }
        if (hasLeadingSpace && !atLineStart) {
          outFile << " [LeadingSpace]";
        }
        outFile << "\tLoc=<" << srcFile << ":" << srcLineNum << ":" << (foundPos + 1) << ">" << std::endl;

        lineCol = foundPos + tokenText.length() + 1;
        found = true;
      } else {
        // 当前行没找到，移到下一行
        logicalLineIdx++;
        lineCol = 1;
      }
    }
  }

  return 0;
}
