#include "SYsULexer.h"
#include <fstream>
#include <iostream>
#include <unordered_map>
#include <sstream>
#include <vector>

std::unordered_map<std::string, std::string> tokenTypeMapping = {
  { "Int", "int" },
  { "Identifier", "identifier" },
  { "LeftParen", "l_paren" },
  { "RightParen", "r_paren" },
  { "RightBrace", "r_brace" },
  { "LeftBrace", "l_brace" },
  { "LeftBracket", "l_square" },
  { "RightBracket", "r_square" },
  { "Constant", "numeric_constant" },
  { "Return", "return" },
  { "Semi", "semi" },
  { "EOF", "eof" },
  { "Equal", "equal" },
  { "Plus", "plus" },
  { "Comma", "comma" },
  { "Void", "void" },
  { "If", "if" },
  { "Else", "else" },
  { "While", "while" },
  { "Break", "break" },
  { "Continue", "continue" },
  { "Const", "const" },
  { "Minus", "minus" },
  { "Star", "star" },
  { "Slash", "slash" },
  { "Percent", "percent" },
