   202	    node->op = node->kComma;
   203	    node->lft = ret;
   204	    node->rht = self(list[i]);
   205	    ret = node;
   206	  }
   207	
   208	  return ret;
   209	}
   210	
   211	Expr*
   212	Ast2Asg::operator()(ast::AssignmentExpressionContext* ctx)
   213	{
   214	  if (auto p = ctx->additiveExpression())
   215	    return self(p);
   216	
   217	  auto ret = make<BinaryExpr>();
   218	  ret->op = ret->kAssign;
   219	  ret->lft = self(ctx->unaryExpression());
   220	  ret->rht = self(ctx->assignmentExpression());
   221	  return ret;
   222	}
   223	Expr*
   224	Ast2Asg::operator()(ast::AdditiveExpressionContext* ctx)
   225	{
   226	  auto children = ctx->children;
   227	  Expr* ret = self(dynamic_cast<ast::UnaryExpressionContext*>(children[0]));
   228	
   229	  for (unsigned i = 1; i < children.size(); ++i) {
   230	    auto node = make<BinaryExpr>();
   231	
   232	    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])
   233	                   ->getSymbol()
   234	                   ->getType();
   235	    switch (token) {
   236	      case ast::Plus:
   237	        node->op = node->kAdd;
   238	        break;
   239	
   240	      case ast::Minus:
   241	        node->op = node->kSub;
   242	        break;
   243	
   244	      default:
   245	        ABORT();
   246	    }
   247	
   248	    node->lft = ret;
   249	    node->rht = self(dynamic_cast<ast::UnaryExpressionContext*>(children[++i]));
   250	    ret = node;
   251	  }
   252	
   253	  return ret;
   254	}
   255	
   256	Expr*
   257	Ast2Asg::operator()(ast::UnaryExpressionContext* ctx)
   258	{
   259	  if (auto p = ctx->postfixExpression())
   260	    return self(p);
   261	
   262	  auto ret = make<UnaryExpr>();
   263	
   264	  switch (
   265	    dynamic_cast<antlr4::tree::TerminalNode*>(ctx->unaryOperator()->children[0])
   266	      ->getSymbol()
   267	      ->getType()) {
   268	    case ast::Plus:
   269	      ret->op = ret->kPos;
   270	      break;
   271	
   272	    case ast::Minus:
   273	      ret->op = ret->kNeg;
   274	      break;
   275	
   276	    default:
   277	      ABORT();
   278	  }
   279	
   280	  ret->sub = self(ctx->unaryExpression());
   281	
   282	  return ret;
   283	}
   284	
   285	Expr*
   286	Ast2Asg::operator()(ast::PostfixExpressionContext* ctx)
   287	{
   288	  auto children = ctx->children;
   289	  auto sub = self(dynamic_cast<ast::PrimaryExpressionContext*>(children[0]));
   290	  return sub;
   291	}
   292	
   293	Expr*
   294	Ast2Asg::operator()(ast::PrimaryExpressionContext* ctx)
   295	{
   296	
   297	  if (auto p = ctx->Identifier()) {
   298	    auto name = p->getText();
   299	    auto ret = make<DeclRefExpr>();
   300	    ret->decl = mSymtbl->resolve(name);
   301	    return ret;
   302	  }
   303	
   304	  if (auto p = ctx->Constant()) {
   305	    auto text = p->getText();
   306	
   307	    auto ret = make<IntegerLiteral>();
   308	
   309	    ASSERT(!text.empty());
   310	    if (text[0] != '0')
   311	      ret->val = std::stoll(text);
   312	
   313	    else if (text.size() == 1)
   314	      ret->val = 0;
   315	
   316	    else if (text[1] == 'x' || text[1] == 'X')
   317	      ret->val = std::stoll(text.substr(2), nullptr, 16);
   318	
   319	    else
   320	      ret->val = std::stoll(text.substr(1), nullptr, 8);
   321	
   322	    return ret;
   323	  }
   324	
   325	  ABORT();
   326	}
   327	
   328	Expr*
   329	Ast2Asg::operator()(ast::InitializerContext* ctx)
   330	{
   331	  if (auto p = ctx->assignmentExpression())
   332	    return self(p);
   333	
   334	  auto ret = make<InitListExpr>();
   335	
   336	  if (auto p = ctx->initializerList()) {
   337	    for (auto&& i : p->initializer()) {
   338	      // 将初始化列表展平
   339	      auto expr = self(i);
   340	      if (auto p = expr->dcst<InitListExpr>()) {
   341	        for (auto&& sub : p->list)
   342	          ret->list.push_back(sub);
   343	      } else {
   344	        ret->list.push_back(expr);
   345	      }
   346	    }
   347	  }
   348	
   349	  return ret;
   350	}
   351	
   352	//==============================================================================
   353	// 语句
   354	//==============================================================================
   355	
   356	Stmt*
   357	Ast2Asg::operator()(ast::StatementContext* ctx)
   358	{
   359	  if (auto p = ctx->compoundStatement())
   360	    return self(p);
   361	
   362	  if (auto p = ctx->expressionStatement())
   363	    return self(p);
   364	
   365	  if (auto p = ctx->jumpStatement())
   366	    return self(p);
   367	
   368	  ABORT();
   369	}
   370	
   371	CompoundStmt*
   372	Ast2Asg::operator()(ast::CompoundStatementContext* ctx)
   373	{
   374	  auto ret = make<CompoundStmt>();
   375	
   376	  if (auto p = ctx->blockItemList()) {
   377	    Symtbl localDecls(self);
   378	
   379	    for (auto&& i : p->blockItem()) {
   380	      if (auto q = i->declaration()) {
   381	        auto sub = make<DeclStmt>();
   382	        sub->decls = self(q);
   383	        ret->subs.push_back(sub);
   384	      }
   385	
   386	      else if (auto q = i->statement())
   387	        ret->subs.push_back(self(q));
   388	
   389	      else
   390	        ABORT();
   391	    }
   392	  }
   393	
   394	  return ret;
   395	}
   396	
   397	Stmt*
   398	Ast2Asg::operator()(ast::ExpressionStatementContext* ctx)
   399	{
   400	  if (auto p = ctx->expression()) {
   401	    auto ret = make<ExprStmt>();
   402	    ret->expr = self(p);
   403	    return ret;
   404	  }
   405	
   406	  return make<NullStmt>();
   407	}
   408	
   409	Stmt*
   410	Ast2Asg::operator()(ast::JumpStatementContext* ctx)
   411	{
   412	  if (ctx->Return()) {
   413	    auto ret = make<ReturnStmt>();
   414	    ret->func = mCurrentFunc;
   415	    if (auto p = ctx->expression())
   416	      ret->expr = self(p);
   417	    return ret;
   418	  }
   419	
   420	  ABORT();
   421	}
   422	
   423	//==============================================================================
   424	// 声明
   425	//==============================================================================
   426	
   427	std::vector<Decl*>
   428	Ast2Asg::operator()(ast::DeclarationContext* ctx)
   429	{
   430	  std::vector<Decl*> ret;
   431	
   432	  auto specs = self(ctx->declarationSpecifiers());
   433	
   434	  if (auto p = ctx->initDeclaratorList()) {
   435	    for (auto&& j : p->initDeclarator())
   436	      ret.push_back(self(j, specs));
   437	  }
   438	
   439	  // 如果 initDeclaratorList 为空则这行声明语句无意义
   440	  return ret;
   441	}
   442	
   443	FunctionDecl*
   444	Ast2Asg::operator()(ast::FunctionDefinitionContext* ctx)
   445	{
   446	  auto ret = make<FunctionDecl>();
   447	  mCurrentFunc = ret;
   448	
   449	  auto type = make<Type>();
   450	  ret->type = type;
   451	
   452	  auto sq = self(ctx->declarationSpecifiers());
   453	  type->spec = sq.first, type->qual = sq.second;
   454	
   455	  auto [texp, name] = self(ctx->directDeclarator(), nullptr);
   456	  auto funcType = make<FunctionType>();
   457	  funcType->sub = texp;
   458	  type->texp = funcType;
   459	  ret->name = std::move(name);
   460	
   461	  Symtbl localDecls(self);
   462	
   463	  // 函数定义在签名之后就加入符号表，以允许递归调用
   464	  (*mSymtbl)[ret->name] = ret;
   465	
   466	  ret->body = self(ctx->compoundStatement());
   467	
   468	  return ret;
   469	}
   470	
   471	Decl*
   472	Ast2Asg::operator()(ast::InitDeclaratorContext* ctx, SpecQual sq)
   473	{
   474	  auto [texp, name] = self(ctx->declarator(), nullptr);
   475	  Decl* ret;
   476	
   477	  if (auto funcType = texp->dcst<FunctionType>()) {
   478	    auto fdecl = make<FunctionDecl>();
   479	    auto type = make<Type>();
   480	    fdecl->type = type;
   481	
   482	    type->spec = sq.first;
   483	    type->qual = sq.second;
   484	    type->texp = funcType;
   485	
   486	    fdecl->name = std::move(name);
   487	    for (auto p : funcType->params) {
   488	      auto paramDecl = make<VarDecl>();
   489	      paramDecl->type = p;
   490	      fdecl->params.push_back(paramDecl);
   491	    }
   492	
   493	    if (ctx->initializer())
   494	      ABORT();
   495	    fdecl->body = nullptr;
   496	
   497	    ret = fdecl;
   498	  }
   499	
   500	  else {
   501	    auto vdecl = make<VarDecl>();
   502	    auto type = make<Type>();
   503	    vdecl->type = type;
   504	
   505	    type->spec = sq.first;
   506	    type->qual = sq.second;
   507	    type->texp = texp;
   508	    vdecl->name = std::move(name);
   509	
   510	    if (auto p = ctx->initializer())
   511	      vdecl->init = self(p);
   512	    else
   513	      vdecl->init = nullptr;
   514	
   515	    ret = vdecl;
   516	  }
   517	
   518	  // 这个实现允许符号重复定义，新定义会取代旧定义
   519	  (*mSymtbl)[ret->name] = ret;
   520	  return ret;
   521	}
   522	
   523	} // namespace asg
   524

action.command:
cat > /workspace/YatCC/task/2/antlr/SYsUParser.g4 << 'G4EOF'
parser grammar SYsUParser;

options {
  tokenVocab=SYsULexer;
}

// Entry point
compilationUnit
    :   translationUnit? EOF
    ;

translationUnit
    :   externalDeclaration+
    ;

externalDeclaration
    :   functionDefinition
    |   declaration
    ;

// Function definition
functionDefinition
    :   declarationSpecifiers directDeclarator '(' parameterTypeList? ')' compoundStatement
    ;

// Declarations
declaration
    :   declarationSpecifiers initDeclaratorList? ';'
    ;

declarationSpecifiers
    :   declarationSpecifier+
    ;

declarationSpecifier
    :   typeSpecifier
    |   typeQualifier
    ;

typeSpecifier
    :   'int'
    |   'void'
    |   'const'
    ;

typeQualifier
    :   'const'
    ;

initDeclaratorList
    :   initDeclarator (',' initDeclarator)*
    ;

initDeclarator
    :   declarator ('=' initializer)?
    ;

declarator
    :   directDeclarator
    ;

directDeclarator
    :   Identifier
    |   directDeclarator '[' assignmentExpression? ']'
    |   directDeclarator '(' parameterTypeList? ')'
    ;

parameterTypeList
    :   parameterList (',' '...')?
    |   'void'
    ;

parameterList
    :   parameterDeclaration (',' parameterDeclaration)*
    ;

parameterDeclaration
    :   declarationSpecifiers declarator
    |   declarationSpecifiers abstractDeclarator?
    ;

abstractDeclarator
    :   directAbstractDeclarator
    ;

directAbstractDeclarator
    :   '[' assignmentExpression? ']'
    |   directAbstractDeclarator '[' assignmentExpression? ']'
    |   '(' ')'
    |   '(' directAbstractDeclarator ')'
    ;

initializer
    :   assignmentExpression
    |   '{' initializerList ','? '}'
    ;

initializerList
    :   designation? initializer (',' designation? initializer)*
    ;

designation
    :   designatorList '='
    ;

designatorList
    :   designator+
    ;

designator
    :   '[' constantExpression ']'
    |   '.' Identifier
    ;

// Statements
statement
    :   compoundStatement
    |   expressionStatement
    |   selectionStatement
    |   iterationStatement
    |   jumpStatement
    ;

compoundStatement
    :   '{' blockItemList? '}'
    ;

blockItemList
    :   blockItem+
    ;

blockItem
    :   statement
    |   declaration
    ;

expressionStatement
    :   expression? ';'
    ;

selectionStatement
    :   'if' '(' expression ')' statement ('else' statement)?
    ;

iterationStatement
    :   'while' '(' expression ')' statement
    |   'for' '(' expression? ';' expression? ';' expression? ')' statement
    ;

jumpStatement
    :   'return' expression? ';'
    |   'break' ';'
    |   'continue' ';'
    ;

// Expressions (precedence from lowest to highest)
expression
    :   assignmentExpression (',' assignmentExpression)*
    ;

assignmentExpression
    :   conditionalExpression
    |   unaryExpression assignmentOperator assignmentExpression
    ;

assignmentOperator
    :   '=' | '+=' | '-=' | '*=' | '/=' | '%=' 
    |   '&=' | '|=' | '^=' | '<<=' | '>>='
    ;

conditionalExpression
    :   logicalOrExpression ('?' expression ':' conditionalExpression)?
    ;

logicalOrExpression
    :   logicalAndExpression ('||' logicalAndExpression)*
    ;

logicalAndExpression
    :   inclusiveOrExpression ('&&' inclusiveOrExpression)*
    ;

inclusiveOrExpression
    :   exclusiveOrExpression ('|' exclusiveOrExpression)*
    ;

exclusiveOrExpression
    :   andExpression ('^' andExpression)*
    ;

andExpression
    :   equalityExpression ('&' equalityExpression)*
    ;

equalityExpression
    :   relationalExpression (('==' | '!=') relationalExpression)*
    ;

relationalExpression
    :   shiftExpression (('<' | '>' | '<=' | '>=') shiftExpression)*
    ;

shiftExpression
    :   additiveExpression (('<<' | '>>') additiveExpression)*
    ;

additiveExpression
    :   multiplicativeExpression (('+' | '-') multiplicativeExpression)*
    ;

multiplicativeExpression
    :   castExpression (('*' | '/' | '%') castExpression)*
    ;

castExpression
    :   '(' typeName ')' castExpression
    |   unaryExpression
    ;

typeName
    :   typeSpecifier abstractDeclarator?
    ;

unaryExpression
    :   postfixExpression
    |   unaryOperator unaryExpression
    |   'sizeof' unaryExpression
    |   'sizeof' '(' typeName ')'
    ;

unaryOperator
    :   '+' | '-' | '!' | '~'
    ;

postfixExpression
    :   primaryExpression
    |   postfixExpression '[' expression ']'
    |   postfixExpression '(' argumentExpressionList? ')'
    |   postfixExpression '.' Identifier
    |   postfixExpression '->' Identifier
    |   postfixExpression '++'
    |   postfixExpression '--'
    ;

primaryExpression
    :   Identifier
    |   Constant
    |   '(' expression ')'
    ;

argumentExpressionList
    :   assignmentExpression (',' assignmentExpression)*
    ;

// Constants and operators (for reference in actions)
Constant
    :   IntegerConstant
    ;

IntegerConstant
    :   DecimalConstant
    |   OctalConstant
    |   HexadecimalConstant
    ;

DecimalConstant
    :   NonzeroDigit Digit*
    ;

OctalConstant
    :   '0' OctalDigit*
    ;

HexadecimalConstant
    :   '0' [xX] HexDigit+
    ;

HexDigit
    :   [0-9a-fA-F]
    ;

NonzeroDigit
    :   [1-9]
    ;

Digit
    :   [0-9]
    ;

OctalDigit
    :   [0-7]
    ;

Identifier
    :   IdentifierNondigit (IdentifierNondigit | Digit)*
    ;

IdentifierNondigit
    :   Nondigit
    ;

Nondigit
    :   [a-zA-Z_]
    ;
G4EOF

