Expr*
Ast2Asg::operator()(ast::ConditionalExpressionContext* ctx)
{
  auto cond = self(ctx->logicalOrExpression());
  if (ctx->Question()) {
    // Ternary operator - simplified handling
    auto trueExpr = self(dynamic_cast<ast::ExpressionContext*>(ctx->expression()));
    auto falseExpr = self(ctx->conditionalExpression());
    // For now, just return condition (ternary needs special handling)
    return cond;
  }
  return cond;
}

Expr*
Ast2Asg::operator()(ast::PostfixExpressionContext* ctx)
{
  if (ctx->postfixExpression()) {
    // Array subscript or function call
    auto base = self(ctx->postfixExpression());
    if (ctx->LeftBracket()) {
      // Array subscript
      auto index = self(ctx->expression());
      auto node = make<BinaryExpr>();
      node->op = node->kIndex;
      node->lft = base;
      node->rht = index;
      return node;
    }
    if (ctx->LeftParen()) {
      // Function call
      auto call = make<CallExpr>();
      call->head = base;
      if (auto args = ctx->argumentExpressionList()) {
        for (auto&& arg : args->assignmentExpression()) {
          call->args.push_back(self(arg));
        }
      }
      return call;
    }
    return base;
  }
  return self(ctx->primaryExpression());
}

Expr*
Ast2Asg::operator()(ast::PrimaryExpressionContext* ctx)
{
  if (auto p = ctx->Identifier()) {
    auto name = p->getText();
    auto ret = make<DeclRefExpr>();
    ret->decl = mSymtbl->resolve(name);
    return ret;
  }
  if (auto p = ctx->Constant()) {
    auto text = p->getText();
    auto ret = make<IntegerLiteral>();
    ASSERT(!text.empty());
    if (text[0] != '0')
      ret->val = std::stoll(text);
    else if (text.size() == 1)
      ret->val = 0;
    else if (text[1] == 'x' || text[1] == 'X')
      ret->val = std::stoll(text.substr(2), nullptr, 16);
    else
      ret->val = std::stoll(text.substr(1), nullptr, 8);
    return ret;
  }
  if (ctx->LeftParen()) {
    auto ret = make<ParenExpr>();
    ret->sub = self(ctx->expression());
    return ret;
  }
  ABORT();
}

//==============================================================================
// Statement handlers
//==============================================================================

Stmt*
Ast2Asg::operator()(ast::SelectionStatementContext* ctx)
{
  auto ret = make<IfStmt>();
  ret->cond = self(ctx->expression());
  ret->thenStmt = self(ctx->statement()[0]);
  if (ctx->Else()) {
    ret->elseStmt = self(ctx->statement()[1]);
  }
  return ret;
}

Stmt*
Ast2Asg::operator()(ast::IterationStatementContext* ctx)
{
  if (ctx->While()) {
    auto ret = make<WhileStmt>();
    ret->cond = self(ctx->expression());
    ret->body = self(ctx->statement());
    return ret;
  }
  // For loop - simplified as while loop
  if (ctx->For()) {
    auto ret = make<WhileStmt>();
    if (ctx->expression().size() >= 2) {
      ret->cond = self(ctx->expression()[1]);
    } else {
      ret->cond = nullptr;
    }
    ret->body = self(ctx->statement());
    return ret;
  }
  ABORT();
}

Stmt*
Ast2Asg::operator()(ast::JumpStatementContext* ctx)
{
  if (ctx->Break()) {
    return make<BreakStmt>();
  }
  if (ctx->Continue()) {
    return make<ContinueStmt>();
  }
  if (ctx->Return()) {
    auto ret = make<ReturnStmt>();
    ret->func = mCurrentFunc;
    if (auto p = ctx->expression())
      ret->expr = self(p);
    return ret;
  }
  ABORT();
}
