//==============================================================================
// Additional expression handlers
//==============================================================================

Expr*
Ast2Asg::operator()(ast::MultiplicativeExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::CastExpressionContext*>(children[0]));

  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])
                   ->getSymbol()
                   ->getType();
    switch (token) {
      case ast::Star:
        node->op = node->kMul;
        break;
      case ast::Slash:
        node->op = node->kDiv;
        break;
      case ast::Percent:
        node->op = node->kMod;
        break;
      default:
        ABORT();
    }
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::CastExpressionContext*>(children[++i]));
    ret = node;
  }
  return ret;
}

Expr*
Ast2Asg::operator()(ast::CastExpressionContext* ctx)
{
  if (ctx->LeftParen()) {
    // Type cast - for now just return the inner expression
    return self(ctx->unaryExpression());
  }
  return self(ctx->unaryExpression());
}

Expr*
Ast2Asg::operator()(ast::RelationalExpressionContext* ctx)
{
  auto children = ctx->children;
  Expr* ret = self(dynamic_cast<ast::ShiftExpressionContext*>(children[0]));

  for (unsigned i = 1; i < children.size(); ++i) {
    auto node = make<BinaryExpr>();
    auto token = dynamic_cast<antlr4::tree::TerminalNode*>(children[i])
                   ->getSymbol()
                   ->getType();
    switch (token) {
      case ast::Less:
        node->op = node->kLt;
        break;
      case ast::Greater:
        node->op = node->kGt;
        break;
      case ast::LessEqual:
        node->op = node->kLe;
        break;
      case ast::GreaterEqual:
        node->op = node->kGe;
        break;
      default:
        ABORT();
    }
    node->lft = ret;
    node->rht = self(dynamic_cast<ast::ShiftExpressionContext*>(children[++i]));
    ret = node;
  }
  return ret;
}

