// Additional declaration handlers
//==============================================================================

void
EmitIR::operator()(Decl* obj)
{
  if (auto p = obj->dcst<FunctionDecl>())
    return self(p);

  if (auto p = obj->dcst<VarDecl>())
    return self(p);

  ABORT();
}

void
EmitIR::operator()(VarDecl* obj)
{
  auto type = self(obj->type);

  // Global variable
  if (mCurFunc == nullptr) {
    auto glob = new llvm::GlobalVariable(
      mMod,
      type,
      false,
      llvm::GlobalVariable::ExternalLinkage,
      nullptr,
      obj->name);

    if (obj->init) {
      auto initVal = self(obj->init);
      glob->setInitializer(llvm::dyn_cast<llvm::Constant>(initVal));
    } else {
      glob->setInitializer(llvm::ConstantInt::get(llvm::dyn_cast<llvm::IntegerType>(type), 0));
